   */
  public static final ProductType ETD_FUTURE = ProductType.of("EtdFuture", "ETD Future");
  /**
   * A {@link EtdOptionSecurity}.
   */
  public static final ProductType ETD_OPTION = ProductType.of("EtdOption", "ETD Option");
